"""Core engine for data-driven API clients."""

import asyncio
from typing import Any, Coroutine, TypeVar

from .authenticated_client import AuthenticatedAPIClient
from .base import BaseAPIClient
from .http_client import HttpxClient, HTTPClientProtocol

__all__ = ["BaseAPIClient", "AuthenticatedAPIClient", "HttpxClient", "HTTPClientProtocol", "run_async_with_cleanup"]

T = TypeVar("T")


async def _run_with_cleanup(client: Any, coro: Coroutine[Any, Any, T]) -> T:
    """Run a coroutine and ensure the client is closed before the event loop closes.

    Args:
        client: The client instance that may need cleanup
        coro: The coroutine to execute

    Returns:
        The result of the coroutine
    """
    try:
        return await coro
    finally:
        if hasattr(client, "close"):
            close_result = client.close()
            if asyncio.iscoroutine(close_result):
                await close_result


def run_async_with_cleanup(client: Any, coro: Coroutine[Any, Any, T]) -> T:
    """Run an async operation with proper client cleanup.
    
    This function ensures that HTTP clients are properly closed before asyncio.run()
    completes and closes the event loop. This prevents "Event loop is closed" errors
    that occur when httpx tries to clean up connections after the loop is closed.
    
    Args:
        client: The client instance (e.g., RuntimeClient, MemoryClient) that needs cleanup
        coro: The coroutine to execute (e.g., client.method_async(...))
        
    Returns:
        The result of the coroutine
        
    Example:
        >>> client = RuntimeClient()
        >>> result = run_async_with_cleanup(client, client.get_async(id="123"))
    """
    return asyncio.run(_run_with_cleanup(client, coro))

